import Foundation

public enum LogLevel: Int, Comparable, Sendable {
    case debug = 0, info, warning, error

    public static func < (lhs: LogLevel, rhs: LogLevel) -> Bool { lhs.rawValue < rhs.rawValue }

    var label: String {
        switch self {
        case .debug: "DEBUG"
        case .info: "INFO"
        case .warning: "WARN"
        case .error: "ERROR"
        }
    }

    public static func from(string: String) -> LogLevel {
        switch string.lowercased() {
        case "debug": .debug
        case "warning", "warn": .warning
        case "error": .error
        default: .info
        }
    }
}

public final class FileLogger: Sendable {
    public let filePath: String
    public let minLevel: LogLevel
    private let maxBytes: UInt64 = 5 * 1024 * 1024
    private nonisolated(unsafe) static let isoFormatter: ISO8601DateFormatter = {
        let f = ISO8601DateFormatter()
        return f
    }()
    private let queue = DispatchQueue(label: "FileLogger.serialQueue")

    public init(filePath: String, minLevel: LogLevel = .info) {
        self.filePath = filePath
        self.minLevel = minLevel
        let dir = (filePath as NSString).deletingLastPathComponent
        do {
            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
        } catch {
            fputs("FileLogger: cannot create log directory \(dir): \(error)\n", stderr)
        }
    }

    public func log(_ level: LogLevel, _ message: String) {
        guard level >= minLevel else { return }
        append(level: level, message: message)
    }

    /// Blocks until all previously submitted log entries have been written to disk.
    /// Intended for tests that inspect log file contents after calling `log()`.
    func waitForPendingWrites() {
        queue.sync {}
    }

    // MARK: - Private

    private func append(level: LogLevel, message: String) {
        queue.async { [self] in
            let timestamp = Self.isoFormatter.string(from: Date())
            let entry = "[\(timestamp)] [\(level.label)] \(message)\n"
            guard let data = entry.data(using: .utf8) else { return }
            if !FileManager.default.fileExists(atPath: self.filePath) {
                FileManager.default.createFile(atPath: self.filePath, contents: nil)
            }

            self.rotateIfNeeded()

            guard let handle = FileHandle(forWritingAtPath: self.filePath) else { return }
            defer { handle.closeFile() }
            handle.seekToEndOfFile()
            handle.write(data)
        }
    }

    private func rotateIfNeeded() {
        guard let attrs = try? FileManager.default.attributesOfItem(atPath: filePath),
              let size = attrs[.size] as? UInt64,
              size > maxBytes else { return }
        let backup = filePath + ".1"
        try? FileManager.default.removeItem(atPath: backup)
        do {
            try FileManager.default.moveItem(atPath: filePath, toPath: backup)
        } catch {
            fputs("FileLogger: rotation failed for \(filePath): \(error)\n", stderr)
        }
        FileManager.default.createFile(atPath: filePath, contents: nil)
    }
}

// MARK: - Shared loggers

public enum Loggers {
    private static let cacheDir: String = {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        return "\(home)/.cache/ai-usages-tracker"
    }()

    private static let level: LogLevel = {
        LogLevel.from(string: ProcessInfo.processInfo.environment["AI_TRACKER_LOG_LEVEL"] ?? "info")
    }()

    public static let app = FileLogger(filePath: "\(cacheDir)/app.log", minLevel: level)
    public static let claude = FileLogger(filePath: "\(cacheDir)/claude-usages-connector.log", minLevel: level)
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("ClaudeActiveAccountMonitor")
struct ClaudeActiveAccountMonitorTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-monitor-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    private func writeConfig(_ json: String, to dir: String) -> String {
        let path = "\(dir)/claude.json"
        try! json.write(toFile: path, atomically: true, encoding: .utf8)
        return path
    }

    private func makeMonitor(dir: String, configPath: String) -> (ClaudeActiveAccountMonitor, UsagesFileManager) {
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fileManager = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
        let monitor = ClaudeActiveAccountMonitor(
            claudeConfigPath: configPath,
            fileManager: fileManager,
            logger: logger,
            interval: .seconds(3600)
        )
        return (monitor, fileManager)
    }

    @Test("checkOnce marks the active account when a valid config exists")
    func checkOnceActivatesMatchingAccount() async {
        let dir = makeTempDir()
        let configPath = writeConfig(
            #"{"oauthAccount":{"emailAddress":"user@example.com"}}"#,
            to: dir
        )
        let (monitor, fileManager) = makeMonitor(dir: dir, configPath: configPath)
        await fileManager.update(with: [
            VendorUsageEntry(vendor: "claude", account: "user@example.com", isActive: false),
            VendorUsageEntry(vendor: "claude", account: "other@example.com", isActive: true),
        ])

        await monitor.checkOnce()

        let result = await fileManager.read()
        let byAccount = Dictionary(uniqueKeysWithValues: result.usages.map { ($0.account, $0.isActive) })
        #expect(byAccount["user@example.com"] == true)
        #expect(byAccount["other@example.com"] == false)
    }

    @Test("checkOnce deactivates all accounts when config has no oauthAccount")
    func checkOnceDeactivatesWhenNoOauth() async {
        let dir = makeTempDir()
        let configPath = writeConfig("{}", to: dir)
        let (monitor, fileManager) = makeMonitor(dir: dir, configPath: configPath)
        await fileManager.update(with: [
            VendorUsageEntry(vendor: "claude", account: "user@example.com", isActive: true),
        ])

        await monitor.checkOnce()

        let result = await fileManager.read()
        #expect(result.usages[0].isActive == false)
    }

    @Test("checkOnce deactivates all accounts when config file is missing")
    func checkOnceDeactivatesWhenFileMissing() async {
        let dir = makeTempDir()
        let (monitor, fileManager) = makeMonitor(dir: dir, configPath: "\(dir)/missing.json")
        await fileManager.update(with: [
            VendorUsageEntry(vendor: "claude", account: "user@example.com", isActive: true),
        ])

        await monitor.checkOnce()

        let result = await fileManager.read()
        #expect(result.usages[0].isActive == false)
    }

    @Test("start/stop idempotence — double start does not crash")
    func startIdempotent() async {
        let dir = makeTempDir()
        let configPath = writeConfig(
            #"{"oauthAccount":{"emailAddress":"user@example.com"}}"#,
            to: dir
        )
        let (monitor, _) = makeMonitor(dir: dir, configPath: configPath)
        await monitor.start()
        await monitor.start()
        await monitor.stop()
    }

    @Test("stop on non-started monitor does not crash")
    func stopBeforeStart() async {
        let dir = makeTempDir()
        let configPath = writeConfig("{}", to: dir)
        let (monitor, _) = makeMonitor(dir: dir, configPath: configPath)
        await monitor.stop()
    }
}

